import{_ as a,o,c as r,a2 as t}from"./chunks/framework.COr20JJv.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lygenealogy/faq.md","filePath":"projects/lygenealogy/faq.md"}'),d={name:"projects/lygenealogy/faq.md"};function n(l,e,s,c,h,i){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><blockquote><p>编辑日期：2026-03-13<br> 以 <a href="https://github.com/quxiangshun/ly-genealogy" target="_blank" rel="noreferrer">GitHub 仓库</a> 为准。</p></blockquote><h2 id="如何修改管理员密码" tabindex="-1">如何修改管理员密码？ <a class="header-anchor" href="#如何修改管理员密码" aria-label="Permalink to &quot;如何修改管理员密码？&quot;">​</a></h2><p>默认账号为 <code>ly-genealogy</code> / <code>123456</code>。首次登录后需在<strong>管理后台</strong>中修改密码（如通过「修改密码」功能）。生产环境部署前建议在配置或初始化脚本中设置强密码。</p><h2 id="数据库文件在哪里" tabindex="-1">数据库文件在哪里？ <a class="header-anchor" href="#数据库文件在哪里" aria-label="Permalink to &quot;数据库文件在哪里？&quot;">​</a></h2><p>SQLite 数据库位于 <strong>server/data/</strong> 目录下（开发时为 <code>packages/server/data/</code>），具体文件名以项目配置为准。首次正常启动 API 后会按需创建库与表。</p><h2 id="开发时要开几个终端" tabindex="-1">开发时要开几个终端？ <a class="header-anchor" href="#开发时要开几个终端" aria-label="Permalink to &quot;开发时要开几个终端？&quot;">​</a></h2><p>需要三个：一个运行 <code>pnpm dev:server</code>（API），一个运行 <code>pnpm dev:web</code>（公共前端），一个运行 <code>pnpm dev:admin</code>（管理后台）。端口分别为 5001、3000、3001。</p><h2 id="生产环境如何部署" tabindex="-1">生产环境如何部署？ <a class="header-anchor" href="#生产环境如何部署" aria-label="Permalink to &quot;生产环境如何部署？&quot;">​</a></h2><p>在本地执行 <code>bash build.sh</code> 得到 <code>genealogy-release.tar.gz</code>，上传到服务器解压后执行 <code>deploy.sh</code>，再用 Caddy 加载项目内 <code>Caddyfile</code>。详见 <a href="/projects/lygenealogy/deployment.html">部署指南</a>。</p><h2 id="姓名显示为星号" tabindex="-1">姓名显示为星号？ <a class="header-anchor" href="#姓名显示为星号" aria-label="Permalink to &quot;姓名显示为星号？&quot;">​</a></h2><p>为保护隐私，系统对成员姓名做脱敏展示（具体规则以当前版本逻辑为准）。可在管理后台查看完整数据。</p><h2 id="如何支持多姓氏或新族谱" tabindex="-1">如何支持多姓氏或新族谱？ <a class="header-anchor" href="#如何支持多姓氏或新族谱" aria-label="Permalink to &quot;如何支持多姓氏或新族谱？&quot;">​</a></h2><p>系统支持多族谱与多姓氏。通过<strong>管理后台</strong>新增族谱并维护成员、字辈等数据；API 与前端会按现有接口展示。</p><h2 id="技术栈与旧版不同" tabindex="-1">技术栈与旧版不同？ <a class="header-anchor" href="#技术栈与旧版不同" aria-label="Permalink to &quot;技术栈与旧版不同？&quot;">​</a></h2><p>当前版本采用 <strong>Node.js</strong> 技术栈（Express + Nuxt 3 + Vue Admin，pnpm Monorepo）。若从旧版（如 Flask 版）迁移，需按仓库提供的迁移说明或自行做数据与配置迁移。</p>',16)])])}const g=a(d,[["render",n]]);export{u as __pageData,g as default};
